args.query:
SELECT oi.Id AS OrderItemId, oi.OrderId, oi.Quantity, oi.UnitPrice, o.OwnerId, o.AccountId
FROM OrderItem oi
JOIN "Order" o ON o.Id = oi.OrderId;

